/*
 * DCC — Repair Sheet Overrides
 *
 * Symptom this fixes: actor / item sheets render as a stripped "name + image"
 * panel with no body (often after an Item Piles mishap that flags every
 * document and forces its sheet). The override lives on the DOCUMENTS
 * (flags.core.sheetClass / flags.item-piles) and/or the world's default sheet
 * map (core.sheetClasses), so it survives disabling the module and restoring
 * a world backup. Clearing it lets the documents fall back to their normal
 * DCC sheets.
 *
 * Safe to run repeatedly. GM only. BACK UP YOUR WORLD FIRST.
 * https://github.com/foundryvtt-dcc/dcc/issues/777
 */
if (!game.user.isGM) {
  ui.notifications.warn('Only a GM can run the DCC sheet-override repair.')
  return
}

// Matches the Item Piles package id in a registered sheet class string
// (e.g. "item-piles.ItemPileInventoryApp") or its document-flag namespace.
const PATTERN = /item-?piles/i

// --- Scan documents -------------------------------------------------------
const targets = []
for (const collection of [game.actors, game.items]) {
  for (const doc of collection) {
    const sheetClass = doc.getFlag('core', 'sheetClass')
    const hasPileFlag = !!doc.flags?.['item-piles']
    if ((typeof sheetClass === 'string' && PATTERN.test(sheetClass)) || hasPileFlag) {
      targets.push({ doc, sheetClass: sheetClass || null, hasPileFlag })
    }
  }
}

// --- Scan the world default sheet map -------------------------------------
const sheetClasses = game.settings.get('core', 'sheetClasses') || {}
const worldDefaults = []
for (const docType of ['Actor', 'Item']) {
  for (const [subtype, cls] of Object.entries(sheetClasses[docType] || {})) {
    if (typeof cls === 'string' && PATTERN.test(cls)) worldDefaults.push(`${docType}.${subtype}`)
  }
}

const actorCount = targets.filter(t => t.doc.documentName === 'Actor').length
const itemCount = targets.filter(t => t.doc.documentName === 'Item').length

if (!targets.length && !worldDefaults.length) {
  ui.notifications.info('DCC: no Item Piles sheet overrides found — nothing to repair.')
  return
}

// --- Confirm --------------------------------------------------------------
const content = `
  <p>This clears Item Piles sheet overrides so documents fall back to their DCC sheets:</p>
  <ul>
    <li><strong>${actorCount}</strong> actor(s)</li>
    <li><strong>${itemCount}</strong> item(s)</li>
    <li><strong>${worldDefaults.length}</strong> world default sheet registration(s)</li>
  </ul>
  <p>For each flagged document it removes <code>flags.core.sheetClass</code> and the
  <code>flags.item-piles</code> data, and strips any Item Piles entry from the world's
  default sheet map. Overrides that do <em>not</em> reference Item Piles are left untouched.</p>
  <p><strong>Back up your world first.</strong> The page reloads when the repair finishes.</p>
`

const confirmed = await foundry.applications.api.DialogV2.confirm({
  window: { title: 'DCC — Repair Sheet Overrides' },
  content,
  modal: true,
  rejectClose: false
})
if (!confirmed) return

// --- Apply ----------------------------------------------------------------
let repaired = 0
const failures = []
for (const { doc, sheetClass, hasPileFlag } of targets) {
  const update = {}
  if (sheetClass) update['flags.core.-=sheetClass'] = null
  if (hasPileFlag) update['flags.-=item-piles'] = null
  if (foundry.utils.isEmpty(update)) continue
  try {
    await doc.update(update)
    repaired++
  } catch (err) {
    console.error(`DCC repair: failed on ${doc.documentName} "${doc.name}" (${doc.id})`, err)
    failures.push(`${doc.documentName} "${doc.name}"`)
  }
}

if (worldDefaults.length) {
  const updated = foundry.utils.deepClone(sheetClasses)
  for (const docType of ['Actor', 'Item']) {
    for (const subtype of Object.keys(updated[docType] || {})) {
      if (typeof updated[docType][subtype] === 'string' && PATTERN.test(updated[docType][subtype])) {
        delete updated[docType][subtype]
      }
    }
  }
  try {
    await game.settings.set('core', 'sheetClasses', updated)
  } catch (err) {
    console.error('DCC repair: failed to update core.sheetClasses', err)
    failures.push('world default sheet map')
  }
}

console.log('DCC sheet-override repair complete.', { repaired, worldDefaults, failures })
if (failures.length) {
  ui.notifications.warn(`DCC repair finished with ${failures.length} failure(s) — see the console (F12). Repaired ${repaired} document(s).`)
} else {
  ui.notifications.info(`DCC repair complete: ${repaired} document(s) cleaned, ${worldDefaults.length} world default(s) reset. Reloading…`)
  setTimeout(() => foundry.utils.debouncedReload(), 1500)
}
